const lead = $input.first().json;

const planNames = {
  emprendedor: 'Emprendedor (Gratis)',
  pro: 'PRO 🔥 ($29/mes — 50% OFF de por vida)',
  business: 'Business Escala ($69/mes)'
};

return {
  email: lead.email,
  name: lead.name || 'Futuro cliente',
  plan: lead.plan || 'pro',
  planName: planNames[lead.plan] || planNames.pro,
  hasDiscount: lead.plan === 'pro' || !lead.plan,
  date: new Date().toLocaleDateString('es-CO', { year: 'numeric', month: 'long', day: 'numeric' })
};

